### Step 1: Initialize the Board

We'll create an 8x8 board where each cell can either be empty, contain a player's piece, or indicate a special square (like a king).

```python
def init_board():
    board = [[None] * 8 for _ in range(8)]
    # Place initial pieces
    for row in [0, 2]:
        for col in range(8):
            if (row + col) % 2 == 1:
                board[row][col] = 'b'  # Black piece
    for row in [7, 5]:
        for col in range(8):
            if (row + col) % 2 == 1:
                board[row][col] = 'r'  # Red piece
    return board

def print_board(board):
    for row in board:
        print(' '.join(row or '.' for cell in row))
```

### Step 2: Define the Rules

We'll need functions to handle moving pieces, capturing, and kinging.

```python
def move_piece(board, from_pos, to_pos):
    piece = board[from_pos[0]][from_pos[1]]
    if piece is None:
        raise ValueError("No piece at the from position")
    if (to_pos[0] + to_pos[1]) % 2 == 0:
        raise ValueError("Cannot move to an empty or already occupied square")
    board[from_pos[0]][from_pos[1]] = None
    board[to_pos[0]][to_pos[1]] = piece

def capture_piece(board, from_pos, to_pos):
    # Simple capture logic for demonstration
    mid_pos = ((from_pos[0] + to_pos[0]) // 2, (from_pos[1] + to_pos[1]) // 2)
    captured_piece = board[mid_pos[0]][mid_pos[1]]
    if captured_piece is None:
        raise ValueError("No piece to capture")
    board[mid_pos[0]][mid_pos[1]] = None
    move_piece(board, from_pos, to_pos)

def king_piece(board, pos):
    piece = board[pos[0]][pos[1]]
    if piece == 'b':
        board[pos[0]][pos[1]] = 'B'
    elif piece == 'r':
        board[pos[0]][pos[1]] = 'R'

